
local k = 96
local data = ""

local function xor_decode(d, k)
    local r = ""
    for i = 1, #d do
        r = r .. string.char(bit32.bxor(string.byte(d,i), k))
    end
    return r
end

local function b64(d)
    local b='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
    d = string.gsub(d, '[^'..b..'=]', '')
    return (d:gsub('.', function(x)
        if x == '=' then return '' end
        local r,f='',(b:find(x)-1)
        for i=6,1,-1 do
            r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0')
        end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x ~= 8 then return '' end
        local c=0
        for i=1,8 do
            c=c+(x:sub(i,i)=='1' and 2^(8-i) or 0)
        end
        return string.char(c)
    end))
end

local decoded = xor_decode(b64(data), k)

local stack = {}

for line in decoded:gmatch("[^\n]+") do
    local op, val = line:match("([^|]+)|(.+)")

    if op == "PRINT" then
        print(loadstring("return " .. val)())
    elseif op == "EXEC" then
        loadstring(val)()
    end
end
